onClick:
{{
    apiBulkUpdateProducts.run()
    .then(() => {
        showAlert(`Successfully updated ${appsmith.store.varBulkData.length} items!`, "success");

        // Clear the data tables from memory
        storeValue('varBulkData', []); 

        // Turn off Bulk Edit Mode
        storeValue('isBulkEditMode', false);

        // Close modal using its specific name string
        closeModal("modalBulkEdit");

        // Clear out the file cache
        resetWidget("fileSmartUpload");

        // Refresh the main table to see the final results
        Products.run(); 
    })
    .catch((err) => {
        showAlert("Failed to update: " + err.message, "error");
    })
}}
